                  }}
                  className={`w-full text-left p-4 rounded-xl border transition-all group ${
                    currentTime >= p.timestamp && currentTime <= p.timestamp + 7
                    ? 'bg-indigo-50 border-indigo-200 dark:bg-indigo-900/30 dark:border-indigo-800'
                    : 'bg-slate-50 dark:bg-slate-900 border-slate-100 dark:border-slate-800 hover:border-indigo-300'
                  }`}
                >
                  <div className="flex justify-between items-start mb-2">
                    <span className="text-[10px] font-bold text-indigo-500 uppercase tracking-widest">Prompt {i + 1}</span>
                    <span className="text-[10px] font-mono text-slate-400">
                      {Math.floor(p.timestamp / 60)}:{(Math.floor(p.timestamp % 60)).toString().padStart(2, '0')}
                    </span>
                  </div>
                  <p className="text-xs font-medium text-slate-700 dark:text-slate-200 group-hover:text-indigo-600 transition-colors italic leading-relaxed">
                    "{p.text}"
                  </p>
                </button>
              ))
            ) : (
              <div className="text-center py-10 opacity-50">
                <p className="text-xs italic">No follow-ups triggered.</p>
              </div>
            )}
          </div>
        </div>
      </aside>
    </div>
  );
};

export default PlaybackScreen;

export type VideoLayout = '9:16' | '16:9' | '3:4' | '1:1';

export type InterviewTrack = 
  | 'Behavioral' 
  | 'Product/Strategy' 
  | 'Data/Analytics' 
  | 'Leadership' 
  | 'Tell me about yourself';

export type Difficulty = 'Easy' | 'Medium' | 'Hard';

export interface Question {
  id: string;
  category: InterviewTrack;
  text: string;
}

export interface AIPrompt {
  timestamp: number;
  text: string;
  id: string;
}

export interface TimedTranscript {
  text: string;
  timestamp: number;
}

export interface RecordingSession {
  blob: Blob;
  url: string;
  startTime: number;
  duration: number;
  prompts: AIPrompt[];
  transcript: string[]; // Chunks for display during recording
  timedTranscript: TimedTranscript[]; // Timestamped chunks for playback highlighting
  fullTranscript?: string; // Compiled text for AI analysis
  track: InterviewTrack;
  difficulty: Difficulty;
  aspectRatio: VideoLayout;
  starterQuestion: string;
  feedback?: string;
}

import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { VideoLayout, InterviewTrack, Difficulty, Question, AIPrompt, RecordingSession, TimedTranscript } from '../types';
import { LAYOUT_CONFIGS } from '../constants';

interface RecordingScreenProps {
  layout: VideoLayout;
  track: InterviewTrack;
  difficulty: Difficulty;
  starterQuestion: Question;
  onFinished: (session: RecordingSession) => void;
  onCancel: () => void;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

const RecordingScreen: React.FC<RecordingScreenProps> = ({
  layout, track, difficulty, starterQuestion, onFinished, onCancel
}) => {
  const [isRecording, setIsRecording] = useState(false);
  const [timer, setTimer] = useState(0);
  const [isCameraReady, setIsCameraReady] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [activePrompt, setActivePrompt] = useState<AIPrompt | null>(null);
  const [transcriptSnippets, setTranscriptSnippets] = useState<string[]>([]);

  const recordingActiveRef = useRef(false);
  const videoRef = useRef<HTMLVideoElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const chunksRef = useRef<Blob[]>([]);
  const timerRef = useRef<number | null>(null);
  const timerValueRef = useRef<number>(0);
  const startTimeRef = useRef<number>(0);
  const fullTranscriptRef = useRef<string>("");
  const timedTranscriptRef = useRef<TimedTranscript[]>([]);
  const promptsHistoryRef = useRef<AIPrompt[]>([]);

  const audioContextRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);

  const startCamera = async () => {
    try {
      const constraints = {
        video: {
          facingMode: 'user',
          aspectRatio: layout === '16:9' ? 1.777 : layout === '9:16' ? 0.5625 : layout === '3:4' ? 0.75 : 1
        },
        audio: true
      };
      const stream = await navigator.mediaDevices.getUserMedia(constraints);
      streamRef.current = stream;
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        setIsCameraReady(true);
      }
    } catch (err: any) {
      console.error(err);
      setError("Unable to access camera or microphone. Please check permissions.");
    }
  };

  useEffect(() => {
    startCamera();
    return () => stopCamera();
  }, [layout]);

  const stopCamera = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
    }
    if (timerRef.current) window.clearInterval(timerRef.current);
    if (audioContextRef.current) audioContextRef.current.close();
  };

  const setupGeminiLive = async () => {
    if (!streamRef.current) return;

    if (!process.env.API_KEY) {
      console.error("Missing API_KEY environment variable.");
      setError("AI Services are currently unavailable (Missing API Key). Please check your environment configuration.");
      return;
    }

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            const source = audioContextRef.current!.createMediaStreamSource(streamRef.current!);
            const scriptProcessor = audioContextRef.current!.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              if (!recordingActiveRef.current) return;
              const inputData = e.inputBuffer.getChannelData(0);
              const l = inputData.length;
              const int16 = new Int16Array(l);
              for (let i = 0; i < l; i++) {
                int16[i] = inputData[i] * 32768;
              }
              const pcmBlob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              };
              sessionPromise.then(s => s.sendRealtimeInput({ media: pcmBlob }));
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextRef.current!.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.outputTranscription) {
              const text = message.serverContent.outputTranscription.text;
              if (text && text.trim().endsWith('?')) {
                const newPrompt: AIPrompt = {
                  id: Math.random().toString(36).substr(2, 9),
                  text: text.trim().slice(0, 100),
                  timestamp: (Date.now() - startTimeRef.current) / 1000
                };
                setActivePrompt(newPrompt);
                promptsHistoryRef.current.push(newPrompt);
                setTimeout(() => setActivePrompt(curr => curr?.id === newPrompt.id ? null : curr), 7000);
              }
            }
            if (message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text;
              if (text) {
                const currentRelTime = (Date.now() - startTimeRef.current) / 1000;
                fullTranscriptRef.current += " " + text;
                timedTranscriptRef.current.push({ text, timestamp: currentRelTime });
                setTranscriptSnippets(prev => [...prev.slice(-3), text]);
              }
            }
          },
          onerror: (e) => {
            console.error("Live session error:", e);
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          outputAudioTranscription: {},
          inputAudioTranscription: {},
          systemInstruction: `You are a silent interviewer. Your only output should be short follow-up questions (under 12 words) that help the user refine their answer. 
          The track is: ${track}. Difficulty: ${difficulty}. The initial question was: ${starterQuestion.text}.`
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error("Gemini Live failed to connect:", err);
    }
  };

  const startRecording = async () => {
    if (!streamRef.current) return;

    chunksRef.current = [];
    fullTranscriptRef.current = "";
    timedTranscriptRef.current = [];
    promptsHistoryRef.current = [];
    timerValueRef.current = 0;

    const mimeType = MediaRecorder.isTypeSupported('video/mp4; codecs="avc1.42E01E, mp4a.40.2"') 
      ? 'video/mp4' 
      : 'video/webm;codecs=vp9,opus';

    const recorder = new MediaRecorder(streamRef.current, { mimeType });
    mediaRecorderRef.current = recorder;

    recorder.ondataavailable = (e) => {
      if (e.data.size > 0) chunksRef.current.push(e.data);
    };

    recorder.onstop = () => {
      const blob = new Blob(chunksRef.current, { type: mimeType });
      const url = URL.createObjectURL(blob);

      onFinished({
        blob,
        url,
        startTime: startTimeRef.current,
        duration: timerValueRef.current,
        prompts: [...promptsHistoryRef.current],
        timedTranscript: [...timedTranscriptRef.current],
        transcript: [], 
        fullTranscript: fullTranscriptRef.current.trim(),
        track,
        difficulty,
        aspectRatio: layout,
        starterQuestion: starterQuestion.text
      });
    };

    startTimeRef.current = Date.now();
    recorder.start(1000);
    recordingActiveRef.current = true;
    setIsRecording(true);
    setTimer(0);
    timerRef.current = window.setInterval(() => {
      timerValueRef.current += 1;
      setTimer(timerValueRef.current);
    }, 1000);

    setupGeminiLive();
  };

  const stopRecording = () => {
    recordingActiveRef.current = false;
    setIsRecording(false);

    if (mediaRecorderRef.current) {
      mediaRecorderRef.current.stop();
    }

    setTimeout(() => {
      if (sessionRef.current) {
        sessionRef.current.close();
      }
    }, 1000);

    if (timerRef.current) window.clearInterval(timerRef.current);
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  if (error) {
    return (
      <div className="flex flex-col items-center justify-center p-12 text-center bg-red-50 dark:bg-red-950/20 rounded-3xl border border-red-100 dark:border-red-900/50 max-w-2xl mx-auto">
        <div className="w-16 h-16 bg-red-100 dark:bg-red-900 rounded-full flex items-center justify-center text-red-600 dark:text-red-400 mb-4">
          <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>
        </div>
        <h3 className="text-xl font-bold text-red-700 dark:text-red-400">Setup Issue</h3>
        <p className="text-red-600 dark:text-red-500 mb-6">{error}</p>
        <button onClick={onCancel} className="px-6 py-2 bg-slate-200 dark:bg-slate-800 rounded-xl font-bold hover:bg-slate-300 transition-colors">Return to Dashboard</button>
      </div>
    );
  }

  return (
    <div className="flex flex-col items-center gap-6 animate-in zoom-in-95 duration-500">
      <div className={`relative w-full ${LAYOUT_CONFIGS[layout]} bg-black rounded-3xl overflow-hidden shadow-2xl border-4 border-slate-200 dark:border-slate-800`}>
        <video 
          ref={videoRef} 
          autoPlay 
          muted 
          playsInline 
          className="w-full h-full object-cover"
          style={{ transform: 'scaleX(-1)' }}
        />

        <div className="absolute inset-0 pointer-events-none p-6 flex flex-col justify-between">
          <div className="flex justify-between items-start">
            <div className="bg-black/50 backdrop-blur-md px-3 py-1 rounded-full text-white text-xs font-bold flex items-center gap-2">
              <div className={`w-2 h-2 rounded-full ${isRecording ? 'bg-red-500 animate-pulse' : 'bg-slate-400'}`} />
              {isRecording ? 'RECORDING' : 'READY'}
              {isRecording && <span className="ml-1 font-mono">{formatTime(timer)}</span>}
            </div>
            <div className="bg-indigo-500 px-3 py-1 rounded-full text-white text-xs font-bold shadow-lg">
              {track} • {difficulty}
            </div>
          </div>

          <div className="flex flex-col items-center gap-4">
            {activePrompt && (
              <div className="bg-white/95 backdrop-blur shadow-2xl p-4 rounded-2xl max-w-sm border-l-4 border-indigo-500 transform animate-in slide-in-from-bottom-2 duration-300 pointer-events-auto">
                <p className="text-slate-900 font-semibold text-sm leading-relaxed italic">
                  "{activePrompt.text}"
                </p>
                <div className="mt-1 text-[10px] text-indigo-500 font-bold uppercase tracking-tighter">Follow-up Question</div>
              </div>
            )}

            <div className="bg-black/40 backdrop-blur-sm p-4 rounded-2xl w-full max-w-md border border-white/10">
              <p className="text-white/90 text-sm italic line-clamp-2">
                "{starterQuestion.text}"
              </p>
            </div>
          </div>
        </div>
      </div>

      <div className="flex items-center gap-4">
        {!isRecording ? (
          <>
            <button 
              onClick={onCancel}
              className="px-6 py-3 bg-slate-200 dark:bg-slate-800 rounded-2xl font-bold hover:bg-slate-300 transition-colors"
            >
              Cancel
            </button>
            <button 
              onClick={startRecording}
              disabled={!isCameraReady}
              className="px-10 py-3 bg-red-600 hover:bg-red-700 text-white rounded-2xl font-bold shadow-lg shadow-red-500/20 transition-all disabled:opacity-50 flex items-center gap-2"
            >
              <div className="w-3 h-3 bg-white rounded-full" />
              Start Practice
            </button>
          </>
        ) : (
          <button 
            onClick={stopRecording}
            className="px-12 py-3 bg-slate-900 dark:bg-white dark:text-slate-900 text-white rounded-2xl font-bold shadow-lg transition-all flex items-center gap-2"
          >
            <div className="w-3 h-3 bg-red-500 rounded-sm" />
            Finish & Review
          </button>
        )}
      </div>

      {isRecording && transcriptSnippets.length > 0 && (
        <div className="w-full max-w-2xl bg-white dark:bg-slate-800 p-4 rounded-2xl border border-slate-100 dark:border-slate-700">
          <h4 className="text-[10px] font-bold uppercase text-slate-400 mb-2">Real-time Transcript</h4>
          <div className="text-sm text-slate-600 dark:text-slate-300 space-y-1">
            {transcriptSnippets.map((s, i) => (
              <p key={i} className={i === transcriptSnippets.length - 1 ? 'opacity-100' : 'opacity-40'}>
                {s}
              </p>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default RecordingScreen;

import React, { useRef, useState, useEffect } from 'react';
import { GoogleGenAI } from '@google/genai';
import { RecordingSession, TimedTranscript } from '../types';
import { LAYOUT_CONFIGS } from '../constants';

interface PlaybackScreenProps {
  session: RecordingSession;
  onNewSession: () => void;
}

const PlaybackScreen: React.FC<PlaybackScreenProps> = ({ session: initialSession, onNewSession }) => {
  const [session, setSession] = useState<RecordingSession>(initialSession);
  const videoRef = useRef<HTMLVideoElement>(null);
  const transcriptContainerRef = useRef<HTMLDivElement>(null);
  const [currentTime, setCurrentTime] = useState(0);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [analysisError, setAnalysisError] = useState<string | null>(null);
  const [activeIndex, setActiveIndex] = useState<number | null>(null);

  useEffect(() => {
    setSession(initialSession);
  }, [initialSession]);

  // Handle Transcript Highlighting and Auto-Scroll
  useEffect(() => {
    const timedTranscript = session.timedTranscript || [];
    if (timedTranscript.length === 0) return;

    // Find the currently active index
    let currentIdx = -1;
    for (let i = 0; i < timedTranscript.length; i++) {
      if (currentTime >= timedTranscript[i].timestamp) {
        currentIdx = i;
      } else {
        break;
      }
    }

    if (currentIdx !== activeIndex) {
      setActiveIndex(currentIdx);

      // Auto-scroll logic
      if (currentIdx !== -1 && transcriptContainerRef.current) {
        const activeElement = transcriptContainerRef.current.querySelector(`[data-index="${currentIdx}"]`);
        if (activeElement) {
          activeElement.scrollIntoView({
            behavior: 'smooth',
            block: 'center',
          });
        }
      }
    }
  }, [currentTime, session.timedTranscript, activeIndex]);

  const handleDownloadVideo = () => {
    const a = document.createElement('a');
    a.href = session.url;
    a.download = `interview-video-${session.track.toLowerCase().replace(/\s+/g, '-')}.mp4`;
    a.click();
  };

  const handleExportTranscript = () => {
    const element = document.createElement("a");
    const text = session.fullTranscript || "No transcript available.";
    const file = new Blob([text], { type: 'text/plain' });
    element.href = URL.createObjectURL(file);
    element.download = `transcript-${session.track.toLowerCase().replace(/\s+/g, '-')}.txt`;
    document.body.appendChild(element);
    element.click();
  };

  const copyToClipboard = () => {
    if (!session.fullTranscript) return;
    navigator.clipboard.writeText(session.fullTranscript);
    alert("Transcript copied to clipboard!");
  };

  const generateFeedback = async () => {
    const transcriptText = session.fullTranscript?.trim();
    if (!transcriptText || transcriptText.length < 10) {
      setAnalysisError("The transcript is too short for a meaningful analysis. Try to speak a bit more next time!");
      return;
    }

    if (!process.env.API_KEY) {
      setAnalysisError("Analysis unavailable: API Key not found in deployment environment.");
      return;
    }

    setIsAnalyzing(true);
    setAnalysisError(null);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const promptText = `
        Act as an expert interview coach. Analyze the following interview response:

        CONTEXT:
        - Track: ${session.track}
        - Difficulty: ${session.difficulty}
        - Starter Question: ${session.starterQuestion}

        TRANSCRIPT:
        "${transcriptText}"

        Please provide a professional feedback report in Markdown:
        1. **Executive Summary**: A summary impression and estimated performance level.
        2. **Content Analysis**: Evaluate the use of the STAR method, technical accuracy (if applicable), and specific metrics mentioned.
        3. **Delivery Analysis**: Comment on clarity, conciseness, and tone based on the transcript.
        4. **Actionable Recommendations**: 3 specific things the user should do to improve this specific answer.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: promptText
      });

      const feedback = response.text || "Analysis complete, but no output was generated.";
      setSession(prev => ({ ...prev, feedback }));
    } catch (err: any) {
      console.error("Analysis failed:", err);
      setAnalysisError(`Analysis failed: ${err.message || 'Check your API configuration'}`);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleTimeUpdate = () => {
    if (videoRef.current) {
      setCurrentTime(videoRef.current.currentTime);
    }
  };

  const seekTo = (timestamp: number) => {
    if (videoRef.current) {
      videoRef.current.currentTime = timestamp;
      videoRef.current.play().catch(() => {});
    }
  };

  const currentPrompt = session.prompts.find(p => 
    currentTime >= p.timestamp && currentTime <= p.timestamp + 7
  );

  return (
    <div className="grid lg:grid-cols-3 gap-8 items-start animate-in fade-in slide-in-from-right-4 duration-500">
      <div className="lg:col-span-2 space-y-6">
        {/* Video Player */}
        <div className={`relative ${LAYOUT_CONFIGS[session.aspectRatio]} bg-black rounded-3xl overflow-hidden shadow-2xl border-4 border-slate-200 dark:border-slate-800`}>
          <video 
            ref={videoRef}
            src={session.url} 
            controls 
            className="w-full h-full object-cover"
            onTimeUpdate={handleTimeUpdate}
          />

          {currentPrompt && (
            <div className="absolute bottom-16 left-1/2 -translate-x-1/2 w-full max-w-sm px-4 pointer-events-none">
              <div className="bg-white/95 backdrop-blur shadow-2xl p-4 rounded-2xl border-l-4 border-indigo-500 animate-in fade-in zoom-in-95">
                <p className="text-slate-900 font-semibold text-sm italic leading-relaxed">
                  "{currentPrompt.text}"
                </p>
                <div className="mt-1 text-[10px] text-indigo-500 font-bold uppercase">AI Follow-up</div>
              </div>
            </div>
          )}
        </div>

        {/* Primary Actions */}
        <div className="flex flex-wrap gap-3">
          <button 
            onClick={handleDownloadVideo}
            className="flex-1 min-w-[120px] bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-3 px-4 rounded-2xl flex items-center justify-center gap-2 transition-all shadow-lg shadow-indigo-500/20 text-sm"
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>
            Save Video
          </button>

          <button 
            onClick={handleExportTranscript}
            className="flex-1 min-w-[120px] bg-slate-800 dark:bg-slate-100 dark:text-slate-900 text-white font-bold py-3 px-4 rounded-2xl flex items-center justify-center gap-2 transition-all shadow-lg text-sm"
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>
            Export Text
          </button>

          {!session.feedback && (
            <button 
              onClick={generateFeedback}
              disabled={isAnalyzing}
              className="flex-1 min-w-[180px] bg-emerald-600 hover:bg-emerald-700 disabled:bg-slate-400 text-white font-bold py-3 px-4 rounded-2xl flex items-center justify-center gap-2 transition-all shadow-lg shadow-emerald-500/20 text-sm"
            >
              {isAnalyzing ? (
                <span className="flex items-center gap-2">
                  <svg className="animate-spin h-4 w-4 text-white" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  Analyzing...
                </span>
              ) : (
                <>
                  <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2a10 10 0 1 0 10 10H12V2z"/><path d="M12 12L2.5 12"/><path d="M12 12l9.5 0"/><path d="M12 12V2.5"/><path d="M12 12l7 7"/><path d="M12 12l-7-7"/></svg>
                  Analyze Performance
                </>
              )}
            </button>
          )}

          <button 
            onClick={onNewSession}
            className="flex-1 min-w-[120px] bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 font-bold py-3 px-4 rounded-2xl hover:bg-slate-50 transition-all text-sm"
          >
            Start Over
          </button>
        </div>

        {analysisError && (
          <div className="p-4 bg-red-50 dark:bg-red-900/20 border border-red-100 dark:border-red-900 rounded-xl text-red-700 dark:text-red-400 text-sm font-medium">
            {analysisError}
          </div>
        )}

        {/* AI Performance Analysis Section */}
        {session.feedback && (
          <div className="bg-white dark:bg-slate-800 rounded-3xl p-6 md:p-8 border border-slate-100 dark:border-slate-700 shadow-sm animate-in fade-in slide-in-from-bottom-4 duration-500">
